  ('pukao-7c4986e7-moex-00311', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司在X1年初以$1,500,000取得機器，估計殘值$300,000，耐用年限6年，採用直線法提列折 舊與成本模式後續衡量。X3 年底該機器之可回收金額為$840,000、X5 年底之可回收金額為 $530,000。假設機器之估計殘值與估計耐用年限均未改變，則X5年底應認列多少減損損失迴轉利 益？', '["$0", "$20,000", "$30,000", "$50,000 | 41530"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 2, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00312', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X9年7月1日以$1,200,000購入乙公司普通股股權30%作為長期投資，乙公司於X9年 9月30日宣告並發放現金股利$300,000，且乙公司X9年度淨利為$900,000。假設淨利平均發生， 則甲公司X9年12月31日對乙公司權益投資帳戶餘額為何？', '["$1,380,000", "$1,290,000", "$1,245,000", "$1,470,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 3, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00313', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '乙公司於X1年12月份以庫藏股票50,000股換入一筆土地，以作為新建廠房用地，該土地上有 一舊車庫，已知乙公司股票每股面額為$10，庫藏股票成本每股$140，交換當日公允價值每股$160， 拆除舊車庫與出售殘料共得淨價款$600,000，則土地的入帳成本為？', '["$6,400,000", "$7,000,000", "$7,400,000", "$8,000,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 4, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00314', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '若無其他資料，下列何者可協助財務報表使用者評估企業自有資金之占比？', '["淨利率", "負債比率", "股東權益報酬率", "應收帳款週轉率"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 5, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00315', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '甲公司於X1年5月1日以每股$30購入庫藏股10,000股，於X1年底公司股價為每股$35，甲公 司於X2年6月30日以每股$36將庫藏股全數再發行。有關前述庫藏股交易之影響，下列敘述何 者正確？', '["X1年底權益將減少$250,000", "X1年度淨利將增加$50,000", "X2年度保留盈餘將增加$10,000", "X2年底權益將增加$360,000"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL),
  ('pukao-7c4986e7-moex-00316', 'pukao-7c4986e7', 'pukao-7c4986e7-moex-110-d35177eb', 'sub-pukao-7c4986e7-02', NULL, 'single_choice', '乙公司於X6年7月初以$270,000購入一台機器，估計耐用年限5年，殘值$20,000，使用直線法 提列折舊與成本模式衡量。X7年底由於經營環境改變，使得該機器之價值有重大跡象顯示已經發 生減損。乙公司於X7年底作減損測試，估計該機器之使用價值為$175,000，公允價值減處分成本 為$165,000，估計耐用年限不變。乙公司X7年應認列之減損損失為？', '["$0", "$14,000", "$20,000", "$30,000"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:35:46+00:00", "source_pdf_sha1": "9548003d6450", "answer_pdf_sha1": "7fb85628be21", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "414", "s": "1102", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "會計學概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "金融保險"}'::jsonb, NULL)
